(()=>{
  if(window.Chart){
    window.__chartJsReadyPromise=Promise.resolve(window.Chart);
    return;
  }

  const sources=[
    "https://cdn.jsdelivr.net/npm/chart.js@4.4.3/dist/chart.umd.min.js",
    "https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.3/chart.umd.min.js"
  ];

  window.__chartJsReadyPromise=new Promise((resolve,reject)=>{
    let idx=0;

    const tryNext=()=>{
      if(window.Chart){ resolve(window.Chart); return; }
      if(idx>=sources.length){ reject(new Error("Не вдалося завантажити Chart.js")); return; }

      const script=document.createElement("script");
      script.src=sources[idx++];
      script.async=true;
      script.onload=()=>{
        if(window.Chart) resolve(window.Chart);
        else tryNext();
      };
      script.onerror=()=>tryNext();
      document.head.appendChild(script);
    };

    tryNext();
  });
})();
